// Identify IPs probing ports or failing logins
let SuspiciousIPs = union 
    (SecurityEvent | where EventID == 4625 | project TimeGenerated, IpAddress, Type="FailedLogin"),
    (NTANetAnalytics | where FlowDirection == "Inbound" and DestPort in (80, 445, 1433, 3306, 3389) | project TimeGenerated, IpAddress = SrcIp, Type="PortProbe")
| summarize EventCount = count() by IpAddress
| where EventCount >= 5;
// Look for successful Windows Logins
let SuccessfulLogins = SecurityEvent
| where EventID == 4624
| where LogonType in (3, 10) 
| where ipv4_is_private(IpAddress) == false
| project SuccessTime = TimeGenerated, IpAddress, TargetUserName, Computer;
// Correlate the two tables
SuccessfulLogins
| join kind=inner (SuspiciousIPs) on IpAddress
| project SuccessTime, IpAddress, TargetUserName, Computer, EventCount
